INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (3, 0.2, "", 6, 1, "", "drama_talk_surprise_loop_shy", 0, "drama_talk_surprise_in_shy", 129811, 6014);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (21, "", "", 6, "", "", 0, 0, "vo_minigame_1013_top_talk_6_002", "vo_minigame_1013", 6015);
